//-------------------------------------------------------------------------
// 청구거래처 팝업 
//-------------------------------------------------------------------------
scwin.f_openPopUpGilgMcht = async function (gubun) {
    var pCode = "";
    var pName = "";

    scwin.gubun = gubun;

    if (gubun == 1) {
        pCode = ed_bilgClntNo.getValue().trim();
        pName = "";
        if ($c.gus.cfIsNull(pCode)) {
            ed_bilgClntNm.setValue("");
            return;
        }
        if (pCode == $c.gus.cfGetHiddenValue(ed_bilgClntNo)) {
            return;
        }
    } else if (gubun == 2) {
        pCode = "";
        pName = ed_bilgClntNm.getValue().trim();
        if ($c.gus.cfIsNull(pName)) {
            ed_bilgClntNo.setValue("");
            return;
        }
        if (pName == $c.gus.cfGetHiddenValue(ed_bilgClntNm)) {
            return;
        }
    } else {
        pCode = ed_bilgClntNo.getValue().trim();
        pName = ed_bilgClntNm.getValue().trim();
    }

    if (gubun != 0) {
        if (!($c.gus.cfGetHiddenValue(ed_bilgClntNo) == "" && $c.gus.cfGetHiddenValue(ed_bilgClntNm) == "")
            || ds_selling_results.getModifiedIndex().length != 0) {

            let ret = await $c.win.confirm("청구거래처를 변경하면 입력한 모든 데이터가 취소됩니다. <br/>계속 진행하시겠습니까?");
            if (!ret) {
                $c.gus.cfSetValue(ed_bilgClntNo, $c.gus.cfGetHiddenValue(ed_bilgClntNo));
                $c.gus.cfSetValue(ed_bilgClntNm, $c.gus.cfGetHiddenValue(ed_bilgClntNm));
                return;
            }
        }
    }

    if(gubun == 3) {
        pCode = ed_bilgClntNo.getValue().trim();
        pName = ed_bilgClntNm.getValue().trim();
    }

    udc_bilgClntNo.setSelectId("retrieveClntInfo"); // XML상의 SELECT ID
    udc_bilgClntNo.cfCommonPopUp(scwin.udc_bilgClntNo_callBackFunc // 콜백 함수
        , pCode // 화면에서의 ??? Code Element의 Value
        , pName // 화면에서의 ??? Name Element의 Value
        , "T" // 결과가 1건 일때 원도우를 AutoClose 여부 (T:Close,F:Opened)
        , '9'
        , "거래처번호,거래처명,,사업자등록번호,요율연결여부,우편번호,주소,상세주소,거래처담당자,"
        , '100,100,0,120,100,0,100,100,100,0'
        , "3,10"
        , ',,CTRT,0'
        , '800'
        , '600'
        , null // 윈도우 위치 Y좌표
        , null // 윈도우 위치 X좌표
        , null // 중복체크여부 ("F")
        , "F" // 전체검색허용여부 ("F")
        , null
        //,"청구거래처,거래처코드,거래처명" // POP-UP Window Title 검색어1,2 ("Win타이틀,첫번검색Nm,두번?검색Nm")
    );
};

//-------------------------------------------------------------------------
// 공통 Popup 처리 : Gubun Code 에 따른 공통 Popup 을 호출한다.
//-------------------------------------------------------------------------
scwin.f_openCommonPopUp = async function (disGubun, pCode, pName, pClose, pAllSearch) {

    switch (disGubun) {
        case 1:
            // 선박명/항차 팝업
            udc_coshipVsslNm.setSelectId("retrieveVsslCdInfo"); // XML상의 SELECT ID
            udc_coshipVsslNm.cfCommonPopUp(scwin.udc_coshipVsslNm_callBackFunc, // 콜백 함수
                pCode, //pCode
                pName, //pName
                pClose, //pWinCloseTF
                null, //pDispCnt
                null, //pTitle
                null, //pWidth
                null, //pHidden
                null, //pWhere
                null, //pW
                null, //pH
                null, //pTop
                null, //pLeft
                null, //pExistTF - 중복체크여부 ("F")
                pAllSearch, //pAllSearchTF - 전체검색허용여부 ("F")
                "선박, 코드, 코드명" //pWtitleSearch - POP-UP Window Title 검색어1,2 ("Win타이틀,첫번검색Nm,두번?검색Nm")
            );

            break;

        case 2:
            // LINE 팝업
            udc_lineCd.setSelectId("retrieveLineInfoList"); // XML상의 SELECT ID
            udc_lineCd.cfCommonPopUp(scwin.udc_lineCd_callBackFunc // 콜백 함수
                , pCode // 화면에서의 ??? Code Element의 Value
                , pName // 화면에서의 ??? Name Element의 Value
                , pClose // 결과가 1건 일때 원도우를 AutoClose 여부 (T:Close,F:Opened)
                , null // 검색 결과 컬럼의 보여주는 개수 (SELECT절의 순서) MAX:10 - default (2)
                , null // Title순서
                , null // 보여주는 각 컬럼들의 폭
                , null // 컬럼중에서 숨기는 컬럼 지정
                , null // SQL절의 WHERE절에 원하는 조건을 선택함 MAX:8개까지 가능
                , null // POP-UP뛰을때 원도우의 사용자 정의 폭
                , null // POP-UP뛰을때 우도우의 사용자 정의 높이
                , null // 윈도우 위치 Y좌표
                , null // 윈도우 위치 X좌표
                , null // 중복체크여부 ("F")
                , pAllSearch // 전체검색허용여부 ("F")
                , "LINE,LINE코드,LINE명" // POP-UP Window Title 검색어1,2 ("Win타이틀,첫번검색Nm,두번?검색Nm")
            );

            break;

        case 4:
            // 선적부두 팝업
            udc_pierDptCd.setSelectId("retrieveWrkPlInfoByKind"); // XML상의 SELECT ID
            udc_pierDptCd.cfCommonPopUp(scwin.udc_pierDptCd_callBackFunc // XML상의 SELECT ID
                , pCode // 화면에서의 ??? Code Element의 Value
                , pName // 화면에서의 ??? Name Element의 Value
