scwin.lfSetReturnValue = function (rtnList, codeObj, nameObj, objArr) {
    // 팝업을 X 버튼으로 닫았을 때
    if (rtnList == null) {
        rtnList = new Array();
        var listLength = 2;
        if (objArr != null) listLength += objArr.length;
        for (var k = 0; k < listLength; k++) {
            rtnList[k] = "";
        }
    }
    // 팝업창 아래의 '닫기' 버튼으로 닫았을 때
    else if (rtnList[0] == "N/A") {
        $c.gus.cfSetValue(codeObj, $c.gus.cfGetHiddenValue(codeObj));
        $c.gus.cfSetValue(nameObj, $c.gus.cfGetHiddenValue(nameObj));

        if (objArr != null) {
            for (var i = 0; i < objArr.length; i++) {
                $c.gus.cfSetValue(objArr[i], $c.gus.cfGetHiddenValue(objArr[i]));
            }
        }

        return 1;
    }

    $c.gus.cfSetValue(codeObj, rtnList[0]);
    $c.gus.cfSetHiddenValue(codeObj, rtnList[0]);

    $c.gus.cfSetValue(nameObj, rtnList[1]);
    $c.gus.cfSetHiddenValue(nameObj, rtnList[1]);

    if (objArr != null) {
        for (var j = 0; j < objArr.length; j++) {
            $c.gus.cfSetValue(objArr[j], rtnList[j + 2]);
            $c.gus.cfSetHiddenValue(objArr[j], rtnList[j + 2]);
        }
    }
    return 0;
}

//-------------------------------------------------------------------------
// 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
//-------------------------------------------------------------------------
scwin.f_chkOpenCommonPopUp = function (inObj, pairObj, disGubun, isCode) {
    // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
    if (!$c.gus.cfCanOpenPopup(inObj, pairObj))
        return;

    // 짝이 되는 오브젝트의 값 제거
    $c.gus.cfClearPairObj(pairObj);

    // 검색어 세팅
    var pVal = $c.gus.cfGetValue(inObj);

    // inObj가 코드 필드일 경우 팝업
    if (isCode == null || isCode == true)
        scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
    // inObj가 코드명 필드일 경우 팝업
    else
        scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');
}

//-------------------------------------------------------------------------
// 항차 Popup 처리 : Gubun Code 에 따른 공통 Popup 을 호출한다.
//-------------------------------------------------------------------------
scwin.f_Cntr_Visibility = function (row) {
    if (ds_cntr_results.getRowCount() == 0) return;

    if (ds_cntr_results.getRowStatus(ds_cntr_results.getRowPosition()) != "C") { //조회 후

        if (lc_planRsltsYn.getValue() == "0") { //작업계획일때 컨테이너 번호 수정 가능 {
            gr_cntr_results.setReadOnly("column", "cntrCntrNo", true);
            gr_cntr_results.setReadOnly("column", "cntrCntrSizCd", true);
            gr_cntr_results.setReadOnly("column", "cntrCntrTypCd", true);
        } else { //작업실적 일때 컨테이너 번호 수정 불가
            if (ds_cntr_results.getCellData(row, "cntrTempCntrNo").substring(0, 3) == "TMP") {

                gr_cntr_results.setReadOnly("column", "cntrCntrNo", false);
                gr_cntr_results.setReadOnly("column", "cntrCntrSizCd", false);
                gr_cntr_results.setReadOnly("column", "cntrCntrTypCd", false);

            } else {
                gr_cntr_results.setReadOnly("column", "cntrCntrNo", true);
                gr_cntr_results.setReadOnly("column", "cntrCntrSizCd", true);
                gr_cntr_results.setReadOnly("column", "cntrCntrTypCd", true);
            }
        }

        if ($c.gus.cfIsNull(ds_cntr_results.getCellData(row, "cntrFlag"))) {
            gr_cntr_results.setReadOnly("column", "cntrCntrSizCd", true);
            gr_cntr_results.setReadOnly("column", "cntrCntrTypCd", true);
            scwin.gr_cntr_results_setHeaderColor("cntrCntrSizCdHd", "txt-black");
            scwin.gr_cntr_results_setHeaderColor("cntrCntrTypCdHd", "txt-black");
        } else {
            gr_cntr_results.setReadOnly("column", "cntrCntrSizCd", false);
            gr_cntr_results.setReadOnly("column", "cntrCntrTypCd", false);
            scwin.gr_cntr_results_setHeaderColor("cntrCntrSizCdHd", "txt-red");
            scwin.gr_cntr_results_setHeaderColor("cntrCntrTypCdHd", "txt-red");
        }
    } else {
        //행추가시
        if (lc_planRsltsYn.getValue() == "0") {//작업계획일때 컨테이너 번호 자동 생성
            gr_cntr_results.setReadOnly("column", "cntrCntrNo", true);
        } else { //작업실적일때 입력가능
            gr_cntr_results.setReadOnly("column", "cntrCntrNo", false);
        }

        if ($c.gus.cfIsNull(ds_cntr_results.getCellData(row, "cntrFlag"))) {
            gr_cntr_results.setReadOnly("column", "cntrCntrSizCd", true);
            gr_cntr_results.setReadOnly("column", "cntrCntrTypCd", true);
            scwin.gr_cntr_results_setHeaderColor("cntrCntrSizCdHd", "txt-black");
            scwin.gr_cntr_results_setHeaderColor("cntrCntrTypCdHd", "txt-black");
        } else {
            gr_cntr_results.setReadOnly("column", "cntrCntrSizCd", false);
            gr_cntr_results.setReadOnly("column", "cntrCntrTypCd", false);
            scwin.gr_cntr_results_setHeaderColor("cntrCntrSizCdHd", "txt-red");
            scwin.gr_cntr_results_setHeaderColor("cntrCntrTypCdHd", "txt-red");
        }
    }
}

