scwin.f_stdAmt = async function (rowGap) {
    //컨테이너 추가시는 미리 계약번호 체크 하기 때문에 문제 없지만 통합매출 체크시를 위해 다시 체크 해 줌
    if (ds_order_results.getCellData(ds_order_results.getRowPosition(), "odrCtrtNo") == "") {
