//-------------------------------------------------------------------------
// 엑셀 업로드
//-------------------------------------------------------------------------
scwin.uploadExcel = async function () {
    ds_cntr_results.setJSON([]);

    // 설정:data.xml 파일 참고
    //op_303_03_03b.xml
    // if(udc_gridMain.getUpExt() == "1") { // csv
    //     let options = {
    //     "fileName" : "gridDataUpload.csv",
    //     "status" : "C",
    //     "useMaxByteLength" : ",",
    //     "type" : "1" ,
    //     "startRowIndex": 0,
    //     "footerExist": "0",
    //     "endColumnIndex" : 10 //TOBE 일부포맷의 정보가 1열만 존재하여 총 열을 지정하도록 추가
    //     };

    //     await $c.data.uploadGridViewCSV(gr_excel, options);
    // } else { // 엑셀
    //     let options = {
    //     "fileName" : "gridDataUpload.xlsx",
    //     "status" : "C",
    //     "useMaxByteLength" : ",",
    //     "type" : "1" ,
    //     "startRowIndex": 0,
    //     "footerExist": "0" ,
    //     "endColumnIndex" : 10 //TOBE 일부포맷의 정보가 1열만 존재하여 총 열을 지정하도록 추가
    //     };
    //     await $c.data.uploadGridViewExcel(gr_excel, options);
    // }

    var ext = udc_excel.getUpExt();
    var options;
    if (ext == "1") {  // xlsx, csv(1) 선택값
        var options = {
            "fileName": "gridDataUpload.csv",
            "status": "C",
            "header": 1,    //헤더의 존재 여부 (0 : 헤더 행의 수 무시하고 전부 업로드, 1 : 헤더 행의 수 만큼 건너 뜀)
            "useMaxByteLength": ",",
            "type": "1",    //[default: 1, 0]데이터 형태 (0이면 실 데이터 형태,1이면 display 표시 방식)
            //"startRowIndex": 0,
            // "hidden": 1,
            // "fillHidden": 1,      //hidden Column에 빈 값을 넣을지를 결정하기 위한 int형 숫자(1이면 hidden Column에 빈 값을 저장하지 않음,0이면 hidden column이 저장되어있지 않은 csv File이라 간주하고 hidden Column에 빈 값을 넣어줌)(hidden이 0인 경우에는 fillhidden은 영향을 끼치지 않음)
            //"delim": ",",     //[default: ',']CSV 파일에서 데이터를 구분할 구분자
            "footerExist": "0"
        };

        await $c.data.uploadGridViewCSV(gr_cntr_results, options); // CSV를 선택하였을 경우

    } else {
        let options = {
            "fileName": "gridDataUpload.xlsx",
            "status": "C",
            "headerExist": 1,
            "useMaxByteLength": ",", //[default: false] ignoreChar 속성으로 설정한 문자를 제외하고 maxByteLength 속성으로 설정한 길이만큼의 데이터만 업로드.
            "type": "1",
            "startRowIndex": 0, //[default: 0] excel파일에서 그리드의 데이터가 시작되는 행의 번호(헤더 포함)
            "footerExist": "0" //[default: 1] excel파일에서 그리드의 데이터에 footer가 있는지 여부(1이면 footer 존재 0이면 없음 기본값은 1 그리드에 footer가 없으면 적용되지 않음)
        };

        await $c.data.uploadGridViewExcel(gr_cntr_results, options); // XLSX를 선택하였을 경우

    }
};

