    if (ds_cntr_results.getRowCount() > 0) {
        ds_cntr_results.setRowPosition(0);
    }

    tbx_totalRows1.setValue(ds_cntr_results.getRowCount());

    //컨테이너 정보 그리드 체크
    scwin.cntrCheck();

